// Static input arrays
const a1 = [1, 2, 3, 2, 1];
const a2 = [1, 2, 3];
const a3 = [1, 2, 3, 4];

// Function to check same unique elements
function haveSameUniqueElements(arr1, arr2) {
    const set1 = new Set(arr1);
    const set2 = new Set(arr2);

    if (set1.size !== set2.size) {
        return false;
    }

    for (let value of set1) {
        if (!set2.has(value)) {
            return false;
        }
    }

    return true;
}

// Print results
console.log("(a1, a2) - " + haveSameUniqueElements(a1, a2));
console.log("(a1, a3) - " + haveSameUniqueElements(a1, a3));
